#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 50000

struct Job {
    int start, end, profit;
};

int compare(const void *a, const void *b) {
    struct Job *job1 = (struct Job *)a;
    struct Job *job2 = (struct Job *)b;
    return job1->end - job2->end;
}

int calculateMaxProfit(int *jobStartTimes, int *jobEndTimes, int *jobProfits, int n) {
    struct Job jobs[n];
    for (int i = 0; i < n; i++) {
        jobs[i].start = jobStartTimes[i];
        jobs[i].end = jobEndTimes[i];
        jobs[i].profit = jobProfits[i];
    }
    qsort(jobs, n, sizeof(struct Job), compare);
    int dp[n];
    dp[0] = jobs[0].profit;
    for (int i = 1; i < n; i++) {
        int incl = jobs[i].profit;
        int lastNonConflicting = -1;
        for (int j = i - 1; j >= 0; j--) {
            if (jobs[j].end <= jobs[i].start) {
                lastNonConflicting = j;
                break;
            }
        }
        if (lastNonConflicting != -1) {
            incl += dp[lastNonConflicting];
        }
        dp[i] = (incl > dp[i - 1]) ? incl : dp[i - 1];
    }
    return dp[n - 1];
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int jobStartTimes[n], jobEndTimes[n], jobProfits[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &jobStartTimes[i]);
        }
        for (int i = 0; i < n; i++) {
            scanf("%d", &jobEndTimes[i]);
        }
        for (int i = 0; i < n; i++) {
            scanf("%d", &jobProfits[i]);
        }
        printf("%d\n", calculateMaxProfit(jobStartTimes, jobEndTimes, jobProfits, n));
    }
    return 0;
}

