import java.util.Arrays;
import java.util.Scanner;

class Job implements Comparable<Job> {
    int start, end, profit;
    Job(int start, int end, int profit) {
        this.start = start;
        this.end = end;
        this.profit = profit;
    }
    @Override
    public int compareTo(Job other) {
        return this.end - other.end;
    }
}

public class Main {
    public static int calculateMaxProfit(int[] jobStartTimes, int[] jobEndTimes, int[] jobProfits, int n) {
        Job[] jobs = new Job[n];
        for (int i = 0; i < n; i++) {
            jobs[i] = new Job(jobStartTimes[i], jobEndTimes[i], jobProfits[i]);
        }
        Arrays.sort(jobs);
        int[] dp = new int[n];
        dp[0] = jobs[0].profit;
        for (int i = 1; i < n; i++) {
            int incl = jobs[i].profit;
            int lastNonConflicting = -1;
            for (int j = i - 1; j >= 0; j--) {
                if (jobs[j].end <= jobs[i].start) {
                    lastNonConflicting = j;
                    break;
                }
            }
            if (lastNonConflicting != -1) {
                incl += dp[lastNonConflicting];
            }
            dp[i] = (incl > dp[i - 1]) ? incl : dp[i - 1];
        }
        return dp[n - 1];
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int n = scanner.nextInt();
            int[] jobStartTimes = new int[n];
            int[] jobEndTimes = new int[n];
            int[] jobProfits = new int[n];
            for (int i = 0; i < n; i++) {
                jobStartTimes[i] = scanner.nextInt();
            }
            for (int i = 0; i < n; i++) {
                jobEndTimes[i] = scanner.nextInt();
            }
            for (int i = 0; i < n; i++) {
                jobProfits[i] = scanner.nextInt();
            }
            System.out.println(calculateMaxProfit(jobStartTimes, jobEndTimes, jobProfits, n));
        }
    }
}

