    for (let i = 0; i < n; i++) {
        jobs.push(new Job(jobStartTimes[i], jobEndTimes[i], jobProfits[i]));
    }
    jobs.sort((a, b) => a.end - b.end);
    let dp = new Array(n).fill(0);
    dp[0] = jobs[0].profit;
    for (let i = 1; i < n; i++) {
        let incl = jobs[i].profit;
        let lastNonConflicting = -1;
        for (let j = i - 1; j >= 0; j--) {
            if (jobs[j].end <= jobs[i].start) {
                lastNonConflicting = j;
                break;
